<h2>Workflow runs por estado</h2><ul><?php foreach((array)($cockpit['workflows_by_status']??[]) as $r): ?><li><?= htmlspecialchars((string)($r['status']??'')) ?>: <?= (int)($r['total']??0) ?></li><?php endforeach; ?></ul>
<?php endif; ?>
